def build_task_rows(prefix: str, *, include_expansion: bool = True) -> list[TaskRow]:
    """Build language-specific catalog rows (slot_id uses given prefix)."""
    rows: list[TaskRow] = []
    for item in _TASK_INDEX:
        n = int(item['task_num'])
        slot = f"{prefix}_{n:03d}"
        mirror = f"pas_{n:03d}" if prefix in {"cs", "java"} else ""
        rows.append(
            (
                slot,
                item['chapter_key'],
                item['title'],
                item['format_ru'],
                item['action'],
                item['pattern_id'],
                item['goal'],
                item['features'],
                item['difficulty'],
                mirror,
            )
        )
    if not include_expansion:
        return rows

    try:
        from algo_v192_plan import V192_EXPANSION_TASK_FIRST, V192_EXPANSION_TASK_LAST
        from v192_expansion_meta import V192_EXPANSION_META
    except ImportError:
        return rows

    core_patterns = {str(item["pattern_id"]).strip() for item in _TASK_INDEX}

    for n in range(V192_EXPANSION_TASK_FIRST, V192_EXPANSION_TASK_LAST + 1):
        pattern = f"task_{n:03d}"
        if pattern in core_patterns:
            continue
        meta = V192_EXPANSION_META.get(pattern)
        if not meta:
            continue
        slot = f"{prefix}_{n:03d}"
        mirror = f"pas_{n:03d}" if prefix in {"cs", "java"} else ""
        concepts = meta.get("expected_concepts") or {}
        raw_features = concepts.get("pascal") or concepts.get("python") or ["program_entry"]
        if isinstance(raw_features, str):
            features = raw_features
        else:
            features = "; ".join(str(item).strip() for item in raw_features if str(item).strip())
        rows.append(
            (
                slot,
                str(meta["chapter_key"]),
                str(meta["title"]),
                str(meta["format_ru"]),
                str(meta["action"]),
                pattern,
                str(meta.get("detailed_description") or meta.get("short_goal") or ""),
                features or "program_entry",
                str(meta.get("difficulty") or "medium"),
                mirror,
            )
        )
    return rows

